/*
 * ═══════════════════════════════════════════════════════════════════════
 *  HANSEPAY — GLOBE ANIMATION
 *  assets/globe.js
 *
 *  !! DO NOT EDIT THIS FILE unless you are specifically working on the
 *  globe animation. Do NOT inline this script into index.html — it lives
 *  here precisely so it is not accidentally overwritten during page edits.
 *
 *  What it does:
 *  - Renders an orthographic canvas globe on <canvas id="globe-canvas">
 *  - Draws land masses as dot fields using inverse-orthographic projection
 *  - Animates a gold arc from Hamburg → GB → US → AE → JP → SG on loop
 *  - Highlights the matching currency chip (.ccy-chip[data-ccy]) on each leg
 *  - Rotates globe view smoothly toward each destination
 *  - Canvas sizing is deferred by one rAF so grid layout is computed first
 *
 *  Dependencies: none. Vanilla JS, Canvas 2D API only.
 * ═══════════════════════════════════════════════════════════════════════
 */
(function(){
  function initGlobe(){
  var canvas=document.getElementById('globe-canvas');
  if(!canvas)return;
  var ctx=canvas.getContext('2d');
  var DPR=window.devicePixelRatio||1;

  /* Size the canvas — defer by one rAF so grid layout is computed */
  var col=canvas.closest('.currencies-globe-wrap')||canvas.parentElement;
  var SIZE=Math.min(col.offsetWidth-32, 480);
  if(SIZE<100){SIZE=420;} /* fallback if layout not yet available */
  canvas.width=SIZE*DPR; canvas.height=SIZE*DPR;
  canvas.style.width=SIZE+'px'; canvas.style.height=SIZE+'px';
  ctx.scale(DPR,DPR);

  var CX=SIZE/2, CY=SIZE/2, R=SIZE*0.497;

  /* Country lat/lng (Hamburg=origin) */
  var LATLNG={
    DE:[53.55,9.99], GB:[51.51,-0.13], US:[40.71,-74.01],
    FR:[48.86,2.35], NL:[52.37,4.90], PL:[52.23,21.01],
    JP:[35.68,139.76], SG:[1.35,103.82], AE:[25.20,55.27],
    AU:[-33.87,151.21], BR:[-23.55,-46.63], IN:[19.08,72.88]
  };
  var ORIGIN=LATLNG.DE;
  var DEST_SEQ=['GB','US','AE','JP','SG'];
  /* Map country → currency code, matched to chip data-ccy attributes */
  var CCY_MAP={GB:'GBP',US:'USD',AE:'AED',JP:'JPY',SG:'SGD'};
  function highlightChip(countryCode){
    document.querySelectorAll('.ccy-chip').forEach(function(c){c.classList.remove('globe-active');});
    var ccy=CCY_MAP[countryCode];
    if(ccy){var chip=document.querySelector('.ccy-chip[data-ccy="'+ccy+'"]');if(chip)chip.classList.add('globe-active');}
  }

  /* Land bands — queried per screen-pixel, no precomputed array */
  var B=[
    /* GREENLAND */          [76,85,[-66,-18]],  [64,78,[-58,-18]],
    /* ICELAND */            [63,67,[-24,-13]],
    /* ALASKA */             [56,71,[-170,-141]],
    /* CANADA WEST */        [49,72,[-140,-95]],
    /* CANADA EAST */        [44,62,[-95,-52]],
    /* US WEST+ROCKIES */    [36,49,[-125,-103]],
    /* US CALIFORNIA */      [32,36,[-122,-114]],
    /* US SOUTHWEST */       [30,38,[-114,-103]],
    /* US GREAT PLAINS */    [28,49,[-103,-93]],
    /* US MIDWEST+EAST */    [30,49,[-93,-79]],
    /* US ATLANTIC COAST */  [30,47,[-81,-67]],
    /* FLORIDA */            [24,30,[-87,-80]],
    /* MEXICO */             [15,32,[-118,-86]],
    /* CENTRAL AMERICA */    [8,18,[-92,-76]],
    /* CUBA */               [19,23,[-85,-74]],
    /* HISPANIOLA */         [17,20,[-74,-68]],
    /* SOUTH AMERICA */      [8,14,[-78,-52]],   [0,10,[-82,-48]],  [-10,2,[-80,-34]],
                             [-22,-8,[-74,-34]], [-40,-20,[-74,-40]],[-56,-38,[-78,-64]],
    /* EUROPE */             [68,74,[14,32]],    [62,70,[4,32]],    [58,64,[4,30]],
                             [54,60,[4,28]],     [50,60,[-10,2]],   [44,54,[-4,26]],
                             [36,46,[-10,4]],    [38,46,[8,18]],    [36,46,[14,28]],
                             [36,44,[26,42]],    [54,70,[24,66]],   [46,56,[24,48]],
    /* RUSSIA/SIBERIA */     [64,74,[28,180]],   [58,66,[50,180]],  [52,60,[56,180]],
                             [46,54,[58,172]],   [40,48,[60,126]],  [38,50,[50,82]],
    /* MIDDLE EAST */        [28,38,[34,52]],    [14,30,[38,60]],   [10,16,[42,52]],
    /* SOUTH ASIA */         [24,38,[60,98]],    [14,26,[70,96]],   [6,16,[76,82]],
    /* CHINA — N/NE */      [38,54,[84,122]],
    /* CHINA — S coast */   [22,38,[98,122]],
    /* TAIWAN */            [21,25,[120,122]],
    /* KOREA */             [34,38,[124,127]],
    /* JAPAN — Kyushu */    [31,34,[129,133]],
    /* JAPAN — Shikoku */   [32,34,[132,135]],
    /* JAPAN — Honshu */    [33,41,[130,142]],
    /* JAPAN — Hokkaido */  [41,46,[140,146]],
    /* SE ASIA */           [18,28,[100,124]],  [10,22,[96,110]],  [0,12,[96,108]],
                             [-8,4,[100,120]],   [-8,2,[106,140]],  [6,20,[116,128]],
    /* AFRICA */             [24,36,[-18,36]],   [14,26,[-18,52]],  [4,16,[-18,50]],
                             [-8,6,[8,44]],      [-20,-6,[10,40]],  [-36,-18,[14,38]],
                             [-26,-12,[44,52]],
    /* AUSTRALIA */          [-14,-8,[128,138]], [-22,-12,[116,142]],
                             [-34,-20,[114,154]],[-42,-32,[114,152]],
    /* NEW ZEALAND */        [-46,-36,[166,180]],
  ];
  function isLand(lat,lng){
    for(var b=0;b<B.length;b++){
      if(lat>=B[b][0]&&lat<=B[b][1]){
        for(var r=2;r<B[b].length;r++){
          if(lng>=B[b][r][0]&&lng<=B[b][r][1]) return true;
        }
      }
    }
    return false;
  }

  /* Orthographic projection */
  function project(lat,lng,lon0,lat0){
    var phi=(lat*Math.PI)/180;
    var lam=((lng-lon0)*Math.PI)/180;
    var phi0=(lat0*Math.PI)/180;
    var cosc=Math.sin(phi0)*Math.sin(phi)+Math.cos(phi0)*Math.cos(phi)*Math.cos(lam);
    return{
      x:Math.cos(phi)*Math.sin(lam),
      y:Math.cos(phi0)*Math.sin(phi)-Math.sin(phi0)*Math.cos(phi)*Math.cos(lam),
      visible:cosc>=-0.05, depth:cosc
    };
  }

  /* Animation state */
  var elapsed=0, destIdx=0;
  var CYCLE=4.2;          // seconds per destination
  var lastTs=null;
  /* Smooth transition between destinations */
  var transT=1;           // 0→1 over TRANS_DUR when switching
  var TRANS_DUR=0.7;
  var fromLon0Base=0, fromLat0=30; // previous view angles for transition

  function getDestLon0Base(idx){
    var d=LATLNG[DEST_SEQ[idx]];
    return ORIGIN[1]*0.35+d[1]*0.65; // bias 65% toward destination
  }
  function getDestLat0(idx){
    var d=LATLNG[DEST_SEQ[idx]];
    return(ORIGIN[0]+d[0])/2*0.6+15;
  }

  function easeInOut(p){return p<0.5?2*p*p:1-Math.pow(-2*p+2,2)/2;}

  /* Arc points along great-circle with lift */
  function buildArc(dest,lon0,lat0){
    var pts=[];
    for(var i=0;i<=60;i++){
      var u=i/60;
      var la=ORIGIN[0]+(dest[0]-ORIGIN[0])*u;
      var ln=ORIGIN[1]+(dest[1]-ORIGIN[1])*u;
      var p=project(la,ln,lon0,lat0);
      var lift=Math.sin(u*Math.PI)*0.16;
      pts.push({x:CX+p.x*R, y:CY-p.y*R-lift*R, visible:p.visible});
    }
    return pts;
  }

  /* Initialise label + chip highlight to match destIdx=0 */
  (function(){
    var dests=document.querySelectorAll('.route-dest');
    dests.forEach(function(d,i){i===0?d.classList.add('active'):d.classList.remove('active');});
    highlightChip(DEST_SEQ[0]);
  })();

  function draw(ts){
    if(!lastTs){
      lastTs=ts;
      fromLon0Base=getDestLon0Base(0);
      fromLat0=getDestLat0(0);
      transT=1;
    }
    var dt=Math.min((ts-lastTs)/1000,0.05); lastTs=ts;
    elapsed+=dt;

    if(elapsed>CYCLE){
      elapsed-=CYCLE;
      /* Store the current view as "from" for the transition */
      fromLon0Base=getDestLon0Base(destIdx);
      fromLat0=getDestLat0(destIdx);
      destIdx=(destIdx+1)%DEST_SEQ.length;
      transT=0;
      /* Sync route label + chip highlight */
      var dests=document.querySelectorAll('.route-dest');
      dests.forEach(function(d,i){i===destIdx?d.classList.add('active'):d.classList.remove('active');});
      highlightChip(DEST_SEQ[destIdx]);
    }

    /* Advance transition */
    if(transT<1) transT=Math.min(1,transT+dt/TRANS_DUR);
    var te=easeInOut(transT);

    var phase=elapsed/CYCLE;
    var t=phase<0.85?easeInOut(phase/0.85):1;

    var dest=LATLNG[DEST_SEQ[destIdx]];
    var toLon0Base=getDestLon0Base(destIdx);
    var toLat0=getDestLat0(destIdx);
    /* Interpolate view center for smooth rotation on switch */
    var lon0Base=fromLon0Base+(toLon0Base-fromLon0Base)*te;
    var lat0=fromLat0+(toLat0-fromLat0)*te;
    var lon0=lon0Base;

    ctx.clearRect(0,0,SIZE,SIZE);

    /* Sphere — matte deep navy, subtle limb darkening at edge */
    var grad=ctx.createRadialGradient(CX*0.60,CY*0.55,0,CX,CY,R);
    grad.addColorStop(0,'#132844');
    grad.addColorStop(0.45,'#0C1D34');
    grad.addColorStop(1,'#060D1A');
    ctx.beginPath();ctx.arc(CX,CY,R,0,Math.PI*2);
    ctx.fillStyle=grad;ctx.fill();

    /* Barely-there specular — just enough to feel dimensional, not shiny */
    var spec=ctx.createRadialGradient(CX*0.62,CY*0.52,0,CX*0.62,CY*0.52,R*0.38);
    spec.addColorStop(0,'rgba(255,255,255,0.028)');
    spec.addColorStop(1,'rgba(255,255,255,0)');
    ctx.beginPath();ctx.arc(CX,CY,R,0,Math.PI*2);
    ctx.fillStyle=spec;ctx.fill();

    /* Clip to sphere */
    ctx.save();
    ctx.beginPath();ctx.arc(CX,CY,R,0,Math.PI*2);ctx.clip();

    /* Land dots — uniform screen-space grid, inverse-projected to lat/lng check */
    /* This guarantees even dot spacing regardless of latitude — no polar clustering */
    var STEP=5, phi0=lat0*Math.PI/180;
    for(var sy=Math.ceil(CY-R);sy<CY+R;sy+=STEP){
      for(var sx=Math.ceil(CX-R);sx<CX+R;sx+=STEP){
        var xn=(sx-CX)/R, yn=(sy-CY)/R;
        var rho2=xn*xn+yn*yn;
        if(rho2>=0.998) continue;
        /* depth = sqrt(1-ρ²): 1 at center, 0 at limb */
        var dep=Math.sqrt(1-rho2);
        /* inverse orthographic → lat/lng */
        var yn2=-yn; /* flip y for sphere coords */
        var sp=dep*Math.sin(phi0)+yn2*Math.cos(phi0);
        sp=sp>1?1:sp<-1?-1:sp;
        var dlat=Math.asin(sp)*180/Math.PI;
        var dlng=lon0+Math.atan2(xn,dep*Math.cos(phi0)-yn2*Math.sin(phi0))*180/Math.PI;
        while(dlng>180)dlng-=360; while(dlng<-180)dlng+=360;
        if(!isLand(dlat,dlng)) continue;
        var op=(0.18+dep*0.76).toFixed(2);
        var dr=0.65+dep*1.1;
        ctx.beginPath();
        ctx.arc(sx,sy,dr,0,Math.PI*2);
        ctx.fillStyle='rgba(141,189,230,'+op+')';
        ctx.fill();
      }
    }

    /* Arc */
    var arcPts=buildArc(dest,lon0,lat0);
    var visArc=arcPts.filter(function(p){return p.visible;});
    var endIdx=Math.floor(t*(visArc.length-1));
    if(visArc.length>1){
      /* Full route ghost — solid, very faint */
      ctx.strokeStyle='rgba(201,169,97,0.18)';ctx.lineWidth=1;ctx.setLineDash([]);
      ctx.beginPath();visArc.forEach(function(p,i){i?ctx.lineTo(p.x,p.y):ctx.moveTo(p.x,p.y);});ctx.stroke();
      /* Drawn portion — crisp gold line */
      if(endIdx>0){
        var drawn=visArc.slice(0,endIdx+1);
        ctx.strokeStyle='rgba(201,169,97,0.88)';ctx.lineWidth=1.4;
        ctx.shadowColor='rgba(201,169,97,0.40)';ctx.shadowBlur=5;
        ctx.beginPath();drawn.forEach(function(p,i){i?ctx.lineTo(p.x,p.y):ctx.moveTo(p.x,p.y);});ctx.stroke();
        ctx.shadowBlur=0;
        /* Arc-tip — small glowing point at the leading edge */
        var tip=drawn[drawn.length-1];
        var tipG=ctx.createRadialGradient(tip.x,tip.y,0,tip.x,tip.y,7);
        tipG.addColorStop(0,'rgba(201,169,97,0.55)');
        tipG.addColorStop(1,'rgba(201,169,97,0)');
        ctx.beginPath();ctx.arc(tip.x,tip.y,7,0,Math.PI*2);ctx.fillStyle=tipG;ctx.fill();
        ctx.beginPath();ctx.arc(tip.x,tip.y,2.2,0,Math.PI*2);ctx.fillStyle='rgba(201,169,97,0.95)';ctx.fill();
      }
    }

    ctx.restore();

    /* Origin marker — Hamburg: clean fixed blue dot */
    var op2=project(ORIGIN[0],ORIGIN[1],lon0,lat0);
    if(op2.visible){
      var ox=CX+op2.x*R, oy=CY-op2.y*R;
      ctx.beginPath();ctx.arc(ox,oy,3.5,0,Math.PI*2);ctx.fillStyle='#8DBDE6';ctx.fill();
      ctx.beginPath();ctx.arc(ox,oy,1.5,0,Math.PI*2);ctx.fillStyle='#fff';ctx.fill();
    }

    /* Destination marker — gold dot, blooms gently on arrival */
    var dp=project(dest[0],dest[1],lon0,lat0);
    if(dp.visible){
      var dx2=CX+dp.x*R, dy2=CY-dp.y*R;
      var arrived=t>0.93;
      if(arrived){
        var bloom=3+Math.abs(Math.sin(ts/600))*6;
        var dg=ctx.createRadialGradient(dx2,dy2,0,dx2,dy2,bloom+4);
        dg.addColorStop(0,'rgba(201,169,97,0.22)');
        dg.addColorStop(1,'rgba(201,169,97,0)');
        ctx.beginPath();ctx.arc(dx2,dy2,bloom+4,0,Math.PI*2);ctx.fillStyle=dg;ctx.fill();
      }
      ctx.beginPath();ctx.arc(dx2,dy2,3.5,0,Math.PI*2);ctx.fillStyle='#C9A961';ctx.fill();
      ctx.beginPath();ctx.arc(dx2,dy2,1.5,0,Math.PI*2);ctx.fillStyle='#fff';ctx.fill();
    }

    requestAnimationFrame(draw);
  }

  requestAnimationFrame(draw);
  } // end initGlobe
  requestAnimationFrame(initGlobe);
})();
